@WebService(serviceName = "OrderProcessingService")
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL, parameterStyle = SOAPBinding.ParameterStyle.BARE)
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(OrderRequest request) {
        if (request == null || request.getItems() == null || request.getItems().isEmpty()) {
            return new OrderResponse(false, "Invalid order request: no items provided.", BigDecimal.ZERO, null);
        }

        BigDecimal total = BigDecimal.ZERO;
        for (OrderItem item : request.getItems()) {
            if (item == null || item.getQuantity() <= 0 || item.getUnitPrice() == null || item.getUnitPrice().compareTo(BigDecimal.ZERO) < 0) {
                return new OrderResponse(false, "Invalid item data in order request.", BigDecimal.ZERO, null);
            }
            BigDecimal lineTotal = item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity()));
            total = total.add(lineTotal);
        }

        total = total.setScale(2, RoundingMode.HALF_UP);

        String orderId = processBusinessOrder(request, total);

        return new OrderResponse(true, "Order processed successfully.", total, orderId);
    }

    private String processBusinessOrder(OrderRequest request, BigDecimal total) {
        return "ORD-" + System.currentTimeMillis();
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/OrderProcessingService", new OrderProcessingService());
    }
}

